command:
$ErrorActionPreference = 'Stop'
$repo = [Environment]::GetEnvironmentVariable('DCOIR_REPO_ROOT','Machine')
if ([string]::IsNullOrWhiteSpace($repo)) { throw 'DCOIR_REPO_ROOT is missing.' }
$script = Join-Path $repo 'chatgpt_staging\exec_scripts\Invoke-WbsPlanScaffoldDeleteQueueCloseout.ps1'
if (-not (Test-Path -LiteralPath $script -PathType Leaf)) { throw "Execution script not found: $script" }
& $script
